    datasetSize: vec3f,
    renderMode: i32,
    normalizedSize: vec3f,
    isoValue: f32,
    frameIndex: u32,
    numChannels: u32,
    windowCenter: f32,
    windowWidth: f32,
    _pad2: vec2f,
    clipMin: vec3f,
    _pad3: f32,
    clipMax: vec3f,
    _pad4: f32,
    _pad5: vec2f,
    channelColors: array<vec4f, 4>,
